"use client"

import * as React from "react"
import { useFrame } from "@react-three/fiber"
import { Environment, Lightformer } from "@react-three/drei"
import * as THREE from "three"

import {
  SceneContainer,
  type SceneContainerProps,
} from "@/components/threecn/scene-container"
import {
  useShadcnTheme,
  type ThemeMode,
} from "@/components/hooks/use-shadcn-theme"

/* ------------------------------------------------------------------ */
/* Proportions (scene units). The real trophy: a draped column pinched */
/* at the waist, two figures with raised arms, a globe resting in the  */
/* upstretched hands, all on a stepped base with two green bands.      */
/* ------------------------------------------------------------------ */

const GLOBE_R = 0.62
const GLOBE_Y = 2.45 // globe center; its lower third nests into the hands
const BODY_TOP = 2.05
/** Vertical shift so the whole piece sits centered on the origin. */
const CENTER_Y = -1.28

/**
 * Silhouette of the body as (radius, height) control points, bottom to top:
 * a draped skirt narrowing to the waist, then swelling through the figures'
 * chests and opening where the arms rise to meet the globe.
 */
const PROFILE: [number, number][] = [
  [0.45, 0.0],
  [0.36, 0.1],
  [0.29, 0.28],
  [0.24, 0.52],
  [0.215, 0.85], // waist
  [0.24, 1.15],
  [0.3, 1.4],
  [0.38, 1.62],
  [0.45, 1.8],
  [0.49, 1.95],
  [0.45, BODY_TOP], // curls back in right under the globe
]

const BODY_ROWS = 200
const BODY_COLS = 160

/* ----------------------------- noise ------------------------------ */

function hash3(x: number, y: number, z: number) {
  const s = Math.sin(x * 127.1 + y * 311.7 + z * 74.7) * 43758.5453
  return s - Math.floor(s)
}

/** Trilinear value noise in [0, 1]. */
function vnoise3(x: number, y: number, z: number) {
  const ix = Math.floor(x)
  const iy = Math.floor(y)
  const iz = Math.floor(z)
  const fx = x - ix
  const fy = y - iy
  const fz = z - iz
  const ux = fx * fx * (3 - 2 * fx)
  const uy = fy * fy * (3 - 2 * fy)
  const uz = fz * fz * (3 - 2 * fz)
  const lerp = (a: number, b: number, t: number) => a + (b - a) * t
  const c00 = lerp(hash3(ix, iy, iz), hash3(ix + 1, iy, iz), ux)
  const c10 = lerp(hash3(ix, iy + 1, iz), hash3(ix + 1, iy + 1, iz), ux)
  const c01 = lerp(hash3(ix, iy, iz + 1), hash3(ix + 1, iy, iz + 1), ux)
  const c11 = lerp(hash3(ix, iy + 1, iz + 1), hash3(ix + 1, iy + 1, iz + 1), ux)
  return lerp(lerp(c00, c10, uy), lerp(c01, c11, uy), uz)
}

function fbm3(x: number, y: number, z: number) {
  let sum = 0
  let amp = 0.5
  let freq = 1
  for (let o = 0; o < 4; o++) {
    sum += amp * vnoise3(x * freq + o * 7.3, y * freq + o * 3.1, z * freq)
    amp *= 0.5
    freq *= 2.1
  }
  return sum // ≈ [0, 1]
}

const smoothstep = (e0: number, e1: number, x: number) => {
  const t = Math.min(1, Math.max(0, (x - e0) / (e1 - e0)))
  return t * t * (3 - 2 * t)
}

/* --------------------------- geometry ----------------------------- */

/**
 * The draped body. On top of the lathe profile: a front/back swell for the
 * two figures (they stand back to back along ±z), spiraling drapery folds,
 * and fine sculptural noise so the gold reads as cast metal, not plastic.
 */
function buildBody(): THREE.BufferGeometry {
  const curve = new THREE.CatmullRomCurve3(
    PROFILE.map(([r, y]) => new THREE.Vector3(r, y, 0))
  )
  const positions = new Float32Array(BODY_ROWS * BODY_COLS * 3)

  for (let i = 0; i < BODY_ROWS; i++) {
    const t = i / (BODY_ROWS - 1)
    const p = curve.getPoint(t)
    const r0 = p.x
    const y = p.y

    // Figures' torsos: strongest at chest height, gone at foot and rim.
    const figEnv = Math.exp(-Math.pow((y - 1.35) / 0.5, 2))
    // Drapery folds live on the skirt and waist, fading toward the arms.
    const foldEnv =
      smoothstep(0.02, 0.2, y) * (1 - 0.75 * smoothstep(1.2, 1.9, y))

    for (let j = 0; j < BODY_COLS; j++) {
      const a = (j / BODY_COLS) * Math.PI * 2
      const sa = Math.sin(a)

      // Two-lobed cross-section → the figures' bodies front and back.
      let r = r0 * (1 + 0.18 * figEnv * sa * sa)
      // Spiraling folds (two frequencies, opposite twists) + cast-metal grain.
      r +=
        foldEnv *
        (0.038 * Math.sin(9 * a + y * 1.6 + 0.8) +
          0.022 * Math.sin(15 * a - y * 2.2 + 3.1))
      r +=
        foldEnv *
        0.03 *
        (fbm3(Math.cos(a) * 1.8, y * 1.3, sa * 1.8) - 0.5)

      const k = (i * BODY_COLS + j) * 3
      positions[k] = r * Math.cos(a)
      positions[k + 1] = y
      positions[k + 2] = r * sa
    }
  }

  const index: number[] = []
  for (let i = 0; i < BODY_ROWS - 1; i++) {
    for (let j = 0; j < BODY_COLS; j++) {
      const a = i * BODY_COLS + j
      const b = i * BODY_COLS + ((j + 1) % BODY_COLS)
      const c = (i + 1) * BODY_COLS + j
      const d = (i + 1) * BODY_COLS + ((j + 1) % BODY_COLS)
      index.push(a, c, b, b, c, d)
    }
  }

  const geo = new THREE.BufferGeometry()
  geo.setAttribute("position", new THREE.BufferAttribute(positions, 3))
  geo.setIndex(index)
  geo.computeVertexNormals()
  return geo
}

/**
 * The globe: continents raised in relief from procedural noise, oceans
 * hatched with fine latitude striations — like the engraved original.
 */
function buildGlobe(): THREE.BufferGeometry {
  const geo = new THREE.SphereGeometry(GLOBE_R, 144, 104)
  const pos = geo.attributes.position as THREE.BufferAttribute
  const dir = new THREE.Vector3()
  for (let i = 0; i < pos.count; i++) {
    dir.fromBufferAttribute(pos, i).normalize()
    const land = fbm3(dir.x * 1.6 + 4.2, dir.y * 1.6, dir.z * 1.6 + 9.7)
    const mask = smoothstep(0.5, 0.57, land)
    const relief =
      mask * (0.035 + 0.04 * fbm3(dir.x * 6, dir.y * 6 + 2.4, dir.z * 6))
    const lat = Math.asin(Math.min(1, Math.max(-1, dir.y)))
    const hatch = (1 - mask) * 0.0045 * Math.sin(lat * 46)
    const r = GLOBE_R + relief + hatch
    pos.setXYZ(i, dir.x * r, dir.y * r, dir.z * r)
  }
  geo.computeVertexNormals()
  return geo
}

/**
 * One raised arm as a curve from shoulder up to the globe's widest flank,
 * so the hands visibly cradle the ball like the original.
 */
function armCurve(sx: number, sz: number): THREE.CatmullRomCurve3 {
  const ex = Math.sign(sx) * 0.585
  return new THREE.CatmullRomCurve3([
    new THREE.Vector3(sx, 1.48, sz),
    new THREE.Vector3(sx * 1.8, 1.85, sz * 0.9),
    new THREE.Vector3(ex * 1.02, 2.18, sz * 0.55),
    new THREE.Vector3(ex, 2.42, sz * 0.5),
  ])
}

/** Shoulder anchors: front figure (+z) and back figure (−z), two arms each. */
const ARMS: [number, number][] = [
  [-0.26, 0.2],
  [0.26, 0.2],
  [-0.26, -0.2],
  [0.26, -0.2],
]

/** Stepped base: gold foot, wide green band, gold ring, green band, gold cap. */
const BASE_STEPS: {
  yTop: number
  h: number
  rTop: number
  rBottom: number
  green: boolean
}[] = [
  { yTop: -0.44, h: 0.08, rTop: 0.72, rBottom: 0.82, green: false },
  { yTop: -0.28, h: 0.16, rTop: 0.6, rBottom: 0.72, green: true },
  { yTop: -0.2, h: 0.08, rTop: 0.57, rBottom: 0.6, green: false },
  { yTop: -0.08, h: 0.12, rTop: 0.5, rBottom: 0.57, green: true },
  { yTop: 0.02, h: 0.1, rTop: 0.44, rBottom: 0.5, green: false },
]

/* --------------------------- confetti ----------------------------- */

function Confetti({
  count,
  speed,
  colors,
}: {
  count: number
  speed: number
  colors: THREE.Color[]
}) {
  const ref = React.useRef<THREE.Points>(null)

  const { positions, colorBuf, vy, sway } = React.useMemo(() => {
    const positions = new Float32Array(count * 3)
    const colorBuf = new Float32Array(count * 3)
    const vy = new Float32Array(count)
    const sway = new Float32Array(count)
    for (let i = 0; i < count; i++) {
      // Deterministic scatter (no Math.random — keeps SSR/replay stable).
      const h = (n: number) => {
        const s = Math.sin(n) * 43758.5453
        return s - Math.floor(s)
      }
      positions[i * 3] = (h(i * 1.7) - 0.5) * 4.2
      positions[i * 3 + 1] = h(i * 2.3) * 5 - 0.5
      positions[i * 3 + 2] = (h(i * 3.1) - 0.5) * 3
      const c = colors[i % colors.length]
      colorBuf[i * 3] = c.r
      colorBuf[i * 3 + 1] = c.g
      colorBuf[i * 3 + 2] = c.b
      vy[i] = 0.35 + h(i * 5.9) * 0.6
      sway[i] = h(i * 7.3) * Math.PI * 2
    }
    return { positions, colorBuf, vy, sway }
  }, [count, colors])

  useFrame(({ clock }, delta) => {
    const pts = ref.current
    if (!pts) return
    const t = clock.getElapsedTime()
    const attr = pts.geometry.attributes.position as THREE.BufferAttribute
    const arr = attr.array as Float32Array
    for (let i = 0; i < count; i++) {
      let y = arr[i * 3 + 1] - vy[i] * speed * delta
      if (y < -2.4) y = 4.6
      arr[i * 3 + 1] = y
      arr[i * 3] += Math.sin(t * 1.5 + sway[i]) * 0.004 * speed
    }
    attr.needsUpdate = true
  })

  return (
    <points key={count} ref={ref} frustumCulled={false}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
        <bufferAttribute attach="attributes-color" args={[colorBuf, 3]} />
      </bufferGeometry>
      <pointsMaterial size={0.05} vertexColors sizeAttenuation transparent opacity={0.9} />
    </points>
  )
}

/* ---------------------------- trophy ------------------------------ */

function Trophy({
  speed,
  gold,
  confetti,
  theme,
}: {
  speed: number
  gold: string
  confetti: number
  theme: ThemeMode
}) {
  const { primaryColor, accentColor, foregroundColor, bgColor } =
    useShadcnTheme(theme)
  const groupRef = React.useRef<THREE.Group>(null)

  const bodyGeo = React.useMemo(() => buildBody(), [])
  const globeGeo = React.useMemo(() => buildGlobe(), [])
  const armGeos = React.useMemo(
    () =>
      ARMS.map(
        ([sx, sz]) => new THREE.TubeGeometry(armCurve(sx, sz), 28, 0.065, 10)
      ),
    []
  )
  const hands = React.useMemo(
    () => ARMS.map(([sx, sz]) => armCurve(sx, sz).getPoint(1)),
    []
  )
  React.useEffect(() => {
    return () => {
      bodyGeo.dispose()
      globeGeo.dispose()
      armGeos.forEach((g) => g.dispose())
    }
  }, [bodyGeo, globeGeo, armGeos])

  const goldColor = React.useMemo(() => new THREE.Color(gold), [gold])
  // Emerald bands, nudged toward the theme background so the trophy settles
  // on the page instead of floating.
  const greenColor = React.useMemo(
    () => new THREE.Color("#0e6b3d").lerp(bgColor, 0.08),
    [bgColor]
  )
  const confettiColors = React.useMemo(
    () => [
      goldColor,
      primaryColor.clone(),
      accentColor.clone(),
      foregroundColor.clone(),
    ],
    [goldColor, primaryColor, accentColor, foregroundColor]
  )

  const goldMat = React.useMemo(
    () =>
      new THREE.MeshStandardMaterial({
        metalness: 1,
        roughness: 0.28,
        envMapIntensity: 1.2,
        emissiveIntensity: 0.05,
        side: THREE.DoubleSide,
      }),
    []
  )
  const greenMat = React.useMemo(
    () =>
      new THREE.MeshStandardMaterial({
        metalness: 0.25,
        roughness: 0.35,
        envMapIntensity: 0.45,
      }),
    []
  )
  React.useEffect(() => {
    goldMat.color.copy(goldColor)
    goldMat.emissive.copy(goldColor)
    greenMat.color.copy(greenColor)
  }, [goldMat, greenMat, goldColor, greenColor])
  React.useEffect(() => {
    return () => {
      goldMat.dispose()
      greenMat.dispose()
    }
  }, [goldMat, greenMat])

  useFrame(({ clock }) => {
    const g = groupRef.current
    if (!g) return
    const t = clock.getElapsedTime()
    g.rotation.y = t * 0.3 * speed
    g.position.y = CENTER_Y + Math.sin(t * 0.8) * 0.04
  })

  return (
    <>
      {/* Local, CDN-free reflections so the gold reads as metal. */}
      <Environment resolution={128} frames={1}>
        <Lightformer
          intensity={2.4}
          position={[0, 3, 3]}
          scale={[7, 7, 1]}
          color="#fff6e0"
        />
        <Lightformer
          intensity={1.4}
          position={[-4, 1, -2]}
          scale={[5, 5, 1]}
          color="#ffd98a"
        />
        <Lightformer
          intensity={1}
          position={[4, -1, 1]}
          scale={[4, 4, 1]}
          color="#ffffff"
        />
      </Environment>

      <group ref={groupRef} position={[0, CENTER_Y, 0]}>
        {/* Draped body with the two figures. */}
        <mesh geometry={bodyGeo} material={goldMat} />

        {/* Raised arms and hands cradling the globe. */}
        {armGeos.map((geo, i) => (
          <mesh key={i} geometry={geo} material={goldMat} />
        ))}
        {hands.map((p, i) => (
          <mesh key={i} position={p} material={goldMat}>
            <sphereGeometry args={[0.085, 16, 12]} />
          </mesh>
        ))}

        {/* Continent-embossed globe. */}
        <mesh geometry={globeGeo} material={goldMat} position={[0, GLOBE_Y, 0]} />

        {/* Stepped base: gold foot, two green bands, gold ring between. */}
        {BASE_STEPS.map((s, i) => (
          <mesh
            key={i}
            position={[0, s.yTop - s.h / 2, 0]}
            material={s.green ? greenMat : goldMat}
          >
            <cylinderGeometry args={[s.rTop, s.rBottom, s.h, 72]} />
          </mesh>
        ))}
      </group>

      {confetti > 0 ? (
        <Confetti count={confetti} speed={speed} colors={confettiColors} />
      ) : null}
    </>
  )
}

export type WorldCupProps = {
  /** Rotation and confetti speed multiplier. */
  speed?: number
  /** Color of the gold. */
  gold?: string
  /** Number of falling confetti particles (0 disables them). */
  confetti?: number
  className?: string
  theme?: ThemeMode
  environment?: SceneContainerProps["environment"]
}

/**
 * The World Cup trophy, modeled procedurally after the original: two sculpted
 * figures rising back to back from a draped, spiraling column, arms raised to
 * hold a continent-embossed globe, on a stepped base with two green bands.
 * It turns slowly under studio light amid a drift of confetti, the confetti
 * and base tinted from your shadcn theme.
 */
export function WorldCup({
  speed = 1,
  gold = "#e3b23c",
  confetti = 90,
  className,
  theme = "auto",
  environment = "studio",
}: WorldCupProps) {
  return (
    <SceneContainer
      className={className}
      theme={theme}
      environment={environment}
      camera={[0, 0.35, 7]}
      fov={40}
    >
      <Trophy speed={speed} gold={gold} confetti={confetti} theme={theme} />
    </SceneContainer>
  )
}

"use client"

import * as React from "react"
import { Canvas } from "@react-three/fiber"
import { OrbitControls } from "@react-three/drei"

import { cn } from "@/lib/utils"
import {
  useShadcnTheme,
  type ThemeMode,
} from "@/components/hooks/use-shadcn-theme"

export type EnvironmentPreset = "studio" | "city" | "dawn" | "night"

type LightRig = {
  ambient: { color: string; intensity: number }
  key: { color: string; intensity: number; position: [number, number, number] }
  fill: { color: string; intensity: number; position: [number, number, number] }
  rim: { color: string; intensity: number; position: [number, number, number] }
}

/**
 * Offline lighting rigs. We avoid drei's <Environment preset> because it
 * fetches HDRIs from a CDN — scenes must work with zero external assets.
 */
const RIGS: Record<EnvironmentPreset, LightRig> = {
  studio: {
    ambient: { color: "#ffffff", intensity: 0.6 },
    key: { color: "#ffffff", intensity: 2.2, position: [5, 6, 5] },
    fill: { color: "#dfe3ff", intensity: 0.8, position: [-6, 2, 4] },
    rim: { color: "#ffffff", intensity: 1.4, position: [0, 4, -6] },
  },
  city: {
    ambient: { color: "#c7d2fe", intensity: 0.7 },
    key: { color: "#e0e7ff", intensity: 1.8, position: [4, 7, 4] },
    fill: { color: "#a5b4fc", intensity: 0.9, position: [-5, 1, 5] },
    rim: { color: "#818cf8", intensity: 1.2, position: [-2, 3, -6] },
  },
  dawn: {
    ambient: { color: "#fde2c8", intensity: 0.5 },
    key: { color: "#ffb27a", intensity: 2.0, position: [6, 4, 4] },
    fill: { color: "#9fb4ff", intensity: 0.7, position: [-5, 2, 4] },
    rim: { color: "#ffd9a8", intensity: 1.0, position: [0, 5, -5] },
  },
  night: {
    ambient: { color: "#1e1b4b", intensity: 0.4 },
    key: { color: "#a78bfa", intensity: 1.6, position: [4, 5, 4] },
    fill: { color: "#4338ca", intensity: 0.6, position: [-5, 1, 4] },
    rim: { color: "#7c3aed", intensity: 1.6, position: [-2, 3, -6] },
  },
}

function Rig({
  preset,
  fog,
  theme,
}: {
  preset: EnvironmentPreset
  fog: boolean
  theme: ThemeMode
}) {
  const { bgColor } = useShadcnTheme(theme)
  const rig = RIGS[preset]

  return (
    <>
      {fog ? <fog attach="fog" args={[bgColor.getHex(), 8, 24]} /> : null}
      <ambientLight color={rig.ambient.color} intensity={rig.ambient.intensity} />
      <directionalLight
        color={rig.key.color}
        intensity={rig.key.intensity}
        position={rig.key.position}
      />
      <directionalLight
        color={rig.fill.color}
        intensity={rig.fill.intensity}
        position={rig.fill.position}
      />
      <pointLight
        color={rig.rim.color}
        intensity={rig.rim.intensity * 12}
        position={rig.rim.position}
        distance={30}
      />
    </>
  )
}

/**
 * Track whether an element is near the viewport. WebGL contexts are a scarce
 * resource (browsers cap them at ~8-16), so scenes only hold one while they are
 * on (or close to) screen. The generous `rootMargin` pre-mounts a scene just
 * before it scrolls into view, avoiding a blank first frame.
 */
function useInView(
  ref: React.RefObject<HTMLElement | null>,
  rootMargin: string
): boolean {
  const [inView, setInView] = React.useState(false)

  React.useEffect(() => {
    const el = ref.current
    if (!el) return
    if (typeof IntersectionObserver === "undefined") {
      // No observer available: render eagerly rather than never mounting.
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setInView(true)
      return
    }
    const observer = new IntersectionObserver(
      ([entry]) => setInView(entry.isIntersecting),
      { rootMargin }
    )
    observer.observe(el)
    return () => observer.disconnect()
  }, [ref, rootMargin])

  return inView
}

export type SceneContainerProps = {
  className?: string
  theme?: ThemeMode
  environment?: EnvironmentPreset
  fog?: boolean
  /** Camera position, defaults to a gentle 3/4 view. */
  camera?: [number, number, number]
  /** Vertical field of view. */
  fov?: number
  children?: React.ReactNode
  /** Rendered as an HTML overlay above the canvas (not inside the 3D scene). */
  overlay?: React.ReactNode
  /**
   * Drag to orbit the camera (rotate only — zoom and pan disabled). Defaults to
   * true. Set false if the scene provides its own controls.
   */
  orbit?: boolean
  /**
   * Mount the WebGL canvas only while it is near the viewport, and tear it down
   * once it scrolls away. Keeps a grid of many scenes from exhausting the
   * browser's WebGL context limit and stops `useFrame` from running offscreen.
   * Defaults to true. Set false for a scene that must always render (e.g. a
   * persistent hero background).
   */
  lazy?: boolean
}

/**
 * The canvas wrapper every threecn scene builds on. Sets up a transparent
 * canvas (so your CSS background shows through), responsive DPR, a themed
 * lighting rig and optional fog.
 */
export function SceneContainer({
  className,
  theme = "auto",
  environment = "studio",
  fog = false,
  camera = [0, 0, 6],
  fov = 45,
  children,
  overlay,
  orbit = true,
  lazy = true,
}: SceneContainerProps) {
  const wrapRef = React.useRef<HTMLDivElement>(null)
  const inView = useInView(wrapRef, "300px")
  const active = lazy ? inView : true

  return (
    <div ref={wrapRef} className={cn("relative h-full w-full", className)}>
      {active ? (
        <Canvas
          dpr={[1, 2]}
          gl={{ antialias: true, alpha: true, powerPreference: "high-performance" }}
          camera={{ position: camera, fov, near: 0.1, far: 100 }}
        >
          <Rig preset={environment} fog={fog} theme={theme} />
          <React.Suspense fallback={null}>{children}</React.Suspense>
          {orbit ? (
            <OrbitControls
              makeDefault
              enablePan={false}
              enableZoom={false}
              enableDamping
              dampingFactor={0.1}
            />
          ) : null}
        </Canvas>
      ) : null}
      {overlay ? <div className="pointer-events-none absolute inset-0">{overlay}</div> : null}
    </div>
  )
}

"use client"

import * as React from "react"
import { Color } from "three"

/**
 * The set of theme-derived colors exposed to R3F scenes.
 * Every value is a live `THREE.Color`, ready to assign to a material.
 */
export type ShadcnThemeColors = {
  primaryColor: Color
  primaryForegroundColor: Color
  bgColor: Color
  foregroundColor: Color
  borderColor: Color
  mutedColor: Color
  accentColor: Color
  isDark: boolean
}

/** CSS custom properties read from `:root` / `.dark`. */
const CSS_VARS = {
  primaryColor: "--primary",
  primaryForegroundColor: "--primary-foreground",
  bgColor: "--background",
  foregroundColor: "--foreground",
  borderColor: "--border",
  mutedColor: "--muted-foreground",
  accentColor: "--accent",
} as const

/**
 * Neutral SSR defaults (a dark-ish indigo palette) used before the DOM is
 * available, so the first paint is never a flash of pure black.
 */
function createDefaults(): ShadcnThemeColors {
  return {
    primaryColor: new Color().setHSL(263 / 360, 0.7, 0.6),
    primaryForegroundColor: new Color().setHSL(0, 0, 0.98),
    bgColor: new Color().setHSL(240 / 360, 0.1, 0.039),
    foregroundColor: new Color().setHSL(0, 0, 0.98),
    borderColor: new Color().setHSL(240 / 360, 0.037, 0.159),
    mutedColor: new Color().setHSL(240 / 360, 0.05, 0.649),
    accentColor: new Color().setHSL(240 / 360, 0.037, 0.159),
    isDark: true,
  }
}

/** Matches a bare shadcn HSL triplet, e.g. "263 70% 50%" (optional "/ alpha"). */
const HSL_TRIPLET = /^-?[\d.]+\s+-?[\d.]+%\s+-?[\d.]+%(\s*\/\s*[\d.]+%?)?$/

/**
 * A lazily-created 1x1 canvas 2D context used to normalise arbitrary CSS
 * colors. The browser's own color parser resolves ANY format the CSS spec
 * supports — including `oklch()` (Tailwind v4 / recent shadcn), `color()`,
 * `hsl()`, `rgb()`, hex and named colors — and serialises the result back as
 * `#rrggbb` / `rgba(...)`, which `THREE.Color.setStyle` understands.
 */
let probeCtx: CanvasRenderingContext2D | null | undefined
function getProbeCtx(): CanvasRenderingContext2D | null {
  if (probeCtx !== undefined) return probeCtx
  if (typeof document === "undefined") return (probeCtx = null)
  probeCtx = document.createElement("canvas").getContext("2d")
  return probeCtx
}

/**
 * Normalise any CSS color string to a form THREE can parse (or `null` if the
 * browser rejects it). Assigning an invalid color to `fillStyle` is a no-op, so
 * we probe with two different sentinels: if the result differs, the input was
 * valid and both reflect its normalised value; if it "sticks" to a sentinel,
 * the input was invalid.
 */
function normalizeColor(input: string): string | null {
  const ctx = getProbeCtx()
  if (!ctx) return null
  ctx.fillStyle = "#000"
  ctx.fillStyle = input
  const a = ctx.fillStyle
  ctx.fillStyle = "#fff"
  ctx.fillStyle = input
  const b = ctx.fillStyle
  return a === b ? a : null
}

/**
 * Parse a raw CSS color (as read from a custom property) into a `THREE.Color`.
 *
 * shadcn ships colors as bare HSL triplets ("263 70% 50%"), which we wrap in
 * `hsl(...)`. Everything else — `oklch()`, `rgb()`, `#hex`, `hsl()`, named — is
 * handed to the browser's parser via a canvas probe, so modern oklch-based
 * themes resolve correctly instead of silently falling back to the default.
 */
function parseColor(raw: string, target: Color): Color {
  const value = raw.trim()
  if (!value) return target

  const candidate = HSL_TRIPLET.test(value) ? `hsl(${value})` : value

  // Preferred path: let the browser resolve any CSS color format.
  const normalized = normalizeColor(candidate)
  if (normalized) {
    try {
      return target.setStyle(normalized)
    } catch {
      /* fall through to the manual paths below */
    }
  }

  // Fallbacks for environments without a canvas (e.g. exotic SSR shims).
  const triplet = value.match(/^(-?[\d.]+)\s+(-?[\d.]+)%\s+(-?[\d.]+)%/)
  if (triplet) {
    const h = parseFloat(triplet[1]) / 360
    const s = parseFloat(triplet[2]) / 100
    const l = parseFloat(triplet[3]) / 100
    return target.setHSL(h, s, l)
  }
  try {
    return target.setStyle(value)
  } catch {
    return target
  }
}

function readColors(previous?: ShadcnThemeColors): ShadcnThemeColors {
  if (typeof window === "undefined" || typeof document === "undefined") {
    return previous ?? createDefaults()
  }

  const root = document.documentElement
  const styles = getComputedStyle(root)
  const base = previous ?? createDefaults()

  const next: ShadcnThemeColors = {
    ...base,
    primaryColor: parseColor(
      styles.getPropertyValue(CSS_VARS.primaryColor),
      base.primaryColor.clone()
    ),
    primaryForegroundColor: parseColor(
      styles.getPropertyValue(CSS_VARS.primaryForegroundColor),
      base.primaryForegroundColor.clone()
    ),
    bgColor: parseColor(
      styles.getPropertyValue(CSS_VARS.bgColor),
      base.bgColor.clone()
    ),
    foregroundColor: parseColor(
      styles.getPropertyValue(CSS_VARS.foregroundColor),
      base.foregroundColor.clone()
    ),
    borderColor: parseColor(
      styles.getPropertyValue(CSS_VARS.borderColor),
      base.borderColor.clone()
    ),
    mutedColor: parseColor(
      styles.getPropertyValue(CSS_VARS.mutedColor),
      base.mutedColor.clone()
    ),
    accentColor: parseColor(
      styles.getPropertyValue(CSS_VARS.accentColor),
      base.accentColor.clone()
    ),
    isDark: root.classList.contains("dark"),
  }

  return next
}

export type ThemeMode = "auto" | "light" | "dark"

/**
 * Bridges your shadcn/ui CSS variables into Three.js.
 *
 * - Reads `--primary`, `--background`, `--border`, ... on mount.
 * - Watches `<html class>` with a MutationObserver and re-reads on dark-mode
 *   toggles (works with next-themes, which flips the `.dark` class).
 * - SSR-safe: returns neutral defaults until the DOM is ready.
 *
 * @param mode `"auto"` (default) tracks the document theme. `"light"` / `"dark"`
 *   force a palette by temporarily toggling a detached probe element.
 */
export function useShadcnTheme(mode: ThemeMode = "auto"): ShadcnThemeColors {
  const [colors, setColors] = React.useState<ShadcnThemeColors>(() =>
    createDefaults()
  )

  React.useEffect(() => {
    if (typeof window === "undefined") return

    // These reads pull the live values out of an external system (the DOM's
    // computed CSS variables), which is a legitimate effect → state sync.
    if (mode !== "auto") {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setColors((prev) => readForcedMode(mode, prev))
      return
    }

    // Initial read once mounted (handles hydration + system theme).
    setColors((prev) => readColors(prev))

    const root = document.documentElement
    const observer = new MutationObserver(() => {
      setColors((prev) => readColors(prev))
    })
    observer.observe(root, {
      attributes: true,
      attributeFilter: ["class", "style", "data-theme"],
    })

    return () => observer.disconnect()
  }, [mode])

  return colors
}

/**
 * Read the palette as it would appear under a forced light/dark mode.
 * We synchronously toggle the `.dark` class on `<html>`, read the computed
 * variables, then restore the original class in the same synchronous block.
 * getComputedStyle forces a style flush, so the values are accurate and the
 * browser never paints the intermediate state (no flicker).
 */
function readForcedMode(
  mode: "light" | "dark",
  previous: ShadcnThemeColors
): ShadcnThemeColors {
  if (typeof document === "undefined") return previous

  const root = document.documentElement
  const wasDark = root.classList.contains("dark")
  const wantDark = mode === "dark"

  if (wantDark !== wasDark) root.classList.toggle("dark", wantDark)
  const result = readColors(previous)
  if (wantDark !== wasDark) root.classList.toggle("dark", wasDark)

  return result
}
